  1→package com.yottastudios.ns.collabspace.workspace.service.thirdparty;
  2→
  3→import com.yottastudios.ns.collabspace.space.vo.SpaceAppRelVo;
  4→import com.yottastudios.ns.collabspace.workspace.dto.MigrationConfig;
  5→import com.yottastudios.ns.collabspace.workspace.dto.SpaceNodeMigrationResult;
  6→import com.yottastudios.ns.collabspace.workspace.enums.MigrationTypeEnum;
  7→import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
  8→import com.yottastudios.ns.collabspace.base.vo.TreeNode;
  9→import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
 10→import lombok.RequiredArgsConstructor;
 11→import lombok.extern.slf4j.Slf4j;
 12→import org.springframework.stereotype.Component;
 13→
 14→import java.util.ArrayList;
 15→import java.util.Collection;
 16→import java.util.List;
 17→import java.util.Set;
 18→import java.util.stream.Collectors;
 19→
 20→/**
 21→ * 执行各应用的相应迁移逻辑
 22→ */
 23→@Slf4j
 24→@Component
 25→@RequiredArgsConstructor
 26→public class ThirdAppMigrationChain {
 27→
 28→    private final List<ThirdAppMigrationService> migrationServices;
 29→
 30→    /**
 31→     * 执行迁移
 32→     * 遍历所有迁移服务，每个服务处理自己支持的节点类型
 33→     *
 34→     * @param spaceNodeTree 要执行迁移的树
 35→     * @param targetSpaceId 要迁移到的空间站
 36→     * @param sourceSpaceId 源空间站
 37→     * @param migrationType 迁移类型
 38→     * @param migrationConfig 迁移配置
 39→     * @return 总的迁移结果
 40→     */
 41→    public SpaceNodeMigrationResult executeMigration(List<TreeNode<SpaceNodeVo>> spaceNodeTree,
 42→                                                     String targetSpaceId,
 43→                                                     String sourceSpaceId,
 44→                                                     MigrationTypeEnum migrationType,
 45→                                                     MigrationConfig migrationConfig) {
 46→        
 47→        if (migrationServices.isEmpty()) {
 48→            log.warn("No migration services found");
 49→            return SpaceNodeMigrationResult.builder()
 50→                    .successCount(0)
 51→                    .failedCount(0)
 52→                    .errorMessage("No migration services available")
 53→                    .build();
 54→        }
 55→
 56→        log.info("Starting migration execution for {} tree nodes, target space: {}, migration type: {}", 
 57→                spaceNodeTree.size(), targetSpaceId, migrationType);
 58→
 59→        SpaceNodeMigrationResult overallResult = SpaceNodeMigrationResult.builder()
 60→                .successCount(0)
 61→                .failedCount(0)
 62→                .build();
 63→
 64→        try {
 65→            for (ThirdAppMigrationService service : migrationServices) {
 66→                if (!service.supportsMigrationType(migrationType)) {
 67→                    continue;
 68→                }
 69→                List<SpaceNodeVo> supportedNodes = filterSpaceNodesByTypes(spaceNodeTree, service.supportedSpaceNodeTypes());
 70→                if (!supportedNodes.isEmpty()) {
 71→                    SpaceNodeMigrationResult result = service.handleMigration(supportedNodes, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);
 72→                    overallResult = mergeResults(overallResult, result);
 73→                }
 74→            }
 75→            log.info("Migration execution completed. Total success: {}, failed: {}, mappings: {}", 
 76→                    overallResult.getSuccessCount(), overallResult.getFailedCount(), overallResult.getNodeIdMapping().size());
 77→            
 78→            return overallResult;
 79→        } catch (Exception e) {
 80→            log.error("Migration execution failed", e);
 81→            return SpaceNodeMigrationResult.builder()
 82→                    .successCount(0)
 83→                    .failedCount(0)
 84→                    .errorMessage(e.getMessage())
 85→                    .build();
 86→        }
 87→    }
 88→
 89→    private List<SpaceNodeVo> filterSpaceNodesByTypes(List<TreeNode<SpaceNodeVo>> roots, Collection<SpaceNodeTypeEnum> targetTypes) {
 90→        Set<Integer> typeValues = targetTypes.stream()
 91→                .map(SpaceNodeTypeEnum::getValue)
 92→                .collect(Collectors.toSet());
 93→        List<SpaceNodeVo> result = new ArrayList<>();
 94→        for (TreeNode<SpaceNodeVo> root : roots) {
 95→            collect(root, typeValues, result);
 96→        }
 97→        return result;
 98→    }
 99→
100→    private void collect(TreeNode<SpaceNodeVo> node, Set<Integer> typeValues, List<SpaceNodeVo> result) {
101→        SpaceNodeVo data = node.getData();
102→        if (data != null && typeValues.contains(data.getType())) {
103→            result.add(data);
104→        }
105→        if (node.getChildren() != null) {
106→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
107→                collect(child, typeValues, result);
108→            }
109→        }
110→    }
111→
112→    private SpaceNodeMigrationResult mergeResults(SpaceNodeMigrationResult result1, SpaceNodeMigrationResult result2) {
113→        if (result2 == null) {
114→            return result1;
115→        }
116→
117→        result1.getNodeIdMapping().putAll(result2.getNodeIdMapping());
118→
119→        result1.setSuccessCount((result1.getSuccessCount() != null ? result1.getSuccessCount() : 0) + 
120→                               (result2.getSuccessCount() != null ? result2.getSuccessCount() : 0));
121→        result1.setFailedCount((result1.getFailedCount() != null ? result1.getFailedCount() : 0) + 
122→                              (result2.getFailedCount() != null ? result2.getFailedCount() : 0));
123→
124→        if (result2.getErrorMessage() != null) {
125→            if (result1.getErrorMessage() != null) {
126→                result1.setErrorMessage(result1.getErrorMessage() + "; " + result2.getErrorMessage());
127→            } else {
128→                result1.setErrorMessage(result2.getErrorMessage());
129→            }
130→        }
131→
132→        return result1;
133→    }
134→}

