152→        log.info("acceptMigrationTask: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, treeSize={}",
153→                taskId, email, targetSpaceId, sourceSpaceId, spaceNodeTree.size());
154→
155→        return taskId;
