403→        if (originalTree == null || originalTree.isEmpty()) {
404→            log.info("No tree nodes to save for space: {}", spaceId);
405→            return;
406→        }
407→
408→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
409→
410→        for (TreeNode<SpaceNodeVo> node : originalTree) {
411→            Long parentId = ROOT_PARENT_ID;
412→            if (spaceId.equals(node.getData().getSpaceId())) {
413→                parentId = node.getParentId();
414→            }
415→            checkCopyName(node, spaceId, parentId);
416→        }
417→
418→        log.info("Completed saving new node tree for space: {}", spaceId);
