44→                                                    MigrationTypeEnum migrationType,
45→                                                    MigrationConfig migrationConfig) {
46→        log.info("Starting Apitable cross-server migration for {} nodes", spaceNodes.size());
47→
48→        if (spaceNodes.isEmpty()) {
49→            log.info("No Apitable nodes found for migration");
50→            return SpaceNodeMigrationResult.builder()
51→                    .successCount(0)
52→                    .failedCount(0)
53→                    .build();
