80→                failedCount++;
81→            }
82→        }
83→
84→        return SpaceNodeMigrationResult.builder()
85→                .nodeIdMapping(nodeIdMapping)
86→                .successCount(successCount)
87→                .failedCount(failedCount)
88→                .build();
89→    }
