72→                if (targetSpaceId.equals(sourceSpaceId)) {
73→                    newNodeId = apitableGrpcClientService.copyFile(userId, targetSpaceId, nodeId);
74→                } else {
75→                    newNodeId = apitableGrpcClientService.copyNodeToSpace(userId, targetSpaceId, "", nodeId, false);
76→                }
77→                // 假如newNodeId 是null/""，认为是复制失败
78→                if (newNodeId == null ||  newNodeId.isEmpty()) {
79→                    throw  new BusinessException("copy file failed, the node id is null or empty");
80→                }
81→                nodeIdMapping.put(nodeId, newNodeId);
82→                successCount++;
83→            } catch (Exception e) {
84→                log.error("Failed to copy node {} to space {}", nodeId, targetSpaceId, e);
85→                failedCount++;
86→            }
87→        }
88→
89→        return SpaceNodeMigrationResult.builder()
90→                .nodeIdMapping(nodeIdMapping)
91→                .successCount(successCount)
92→                .failedCount(failedCount)
93→                .build();
94→    }
95→
96→}

