 51→
 52→@Slf4j
 53→@Component
 54→@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
 55→public class SpaceNodeMigrationConsumer {
 56→
 57→    @Resource
 58→    private ISpaceNodeMigrationTaskService spaceNodeMigrationTaskService;
 59→    
 60→    @Resource
 61→    private ObjectMapper objectMapper;
 62→    
 63→    @Resource
 64→    private ThirdAppMigrationChain appMigrationChain;
 65→
 66→    @Resource
 67→    private TreeNodeTemplate treeNodeTemplate;
 68→
 69→    @Resource
 70→    private ISpaceNodeService spaceNodeService;
 71→
 72→    @Resource
 73→    private IApitableGrpcClientService apitableGrpcClientService;
 74→
 75→    @Resource
 76→    private SpaceQueryManager spaceQueryManager;
 77→
 78→    @Resource
 79→    private SpaceNodeUpdateManager spaceNodeUpdateManager;
 80→
 81→    abstract static class TreeNodeMixin<T extends RelIdProvider> {
 82→        @JsonProperty("children")
 83→        @JsonDeserialize(contentAs = TreeNode.class)
 84→        abstract List<TreeNode<T>> getChildren();
 85→
 86→        @JsonProperty("children")
 87→        abstract void setChildren(List<TreeNode<T>> children);
 88→    }
 89→
 90→    @RabbitListener(queues = SPACE_NODE_MIGRATION_QUEUE)
 91→    public void handle(Message message, Channel channel) throws IOException {
 92→        String body = new String(message.getBody());
 93→        log.info("Received space node migration task message: {}", body);
 94→
 95→        SpaceNodeMigrationMessage messageDto = JSONUtil.toBean(body, SpaceNodeMigrationMessage.class);
 96→        String taskId = messageDto.getTaskId();
 97→
 98→        try {
 99→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
100→            ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
101→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.PROCESSING.getValue());
102→            spaceNodeMigrationTaskService.updateById(task);
103→
104→            executeTask(task);
105→
106→            task.setStatus(SpaceNodeMigrationTaskStatusEnum.COMPLETED.getValue());
107→            spaceNodeMigrationTaskService.updateById(task);
108→
109→        } catch (Exception e) {
110→            log.error("Failed to process space node migration task: taskId={}, error={}", taskId, e.getMessage(), e);
111→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
112→            if (task != null) {
113→                task.setStatus(SpaceNodeMigrationTaskStatusEnum.FAILED.getValue());
114→                task.setErrorMessage(e.getMessage());
115→                spaceNodeMigrationTaskService.updateById(task);
116→            }
117→        } finally {
118→            // 先不考虑重试
119→            long deliveryTag = message.getMessageProperties().getDeliveryTag();
120→            channel.basicAck(deliveryTag, false);
121→        }
122→    }
123→
124→    private void executeTask(SpaceNodeMigrationTaskEntity task) throws IOException {
125→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(task.getEmail());
126→        ExceptionUtil.isNotNull(user, SpaceNodeMigrationException.OPERATOR_NOT_EXIST);
127→        Long userId = user.getId();
128→        // 鉴权
129→        if (!spaceQueryManager.isUserSpaceAdmin(userId, task.getTargetSpaceId())) {
130→            throw new BusinessException(AuthException.UNAUTHORIZED);
131→        }
132→
133→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = deserializeTree(task.getOriginTree());
134→        List<SpaceAppRelVo> sourceSpaceAppRels = JSONUtil.toList(task.getSourceSpaceAppRels(), SpaceAppRelVo.class);
135→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(task.getType());
136→
137→        log.info("executeTask: taskId={}, treeSize={}, type: {}, appRels: {}", task.getTaskId(), spaceNodeTree.size(), migrationType.getDescription(), task.getSourceSpaceAppRels());
138→
139→        MigrationConfig migrationConfig = MigrationConfig.builder()
140→                .email(task.getEmail())
141→                .sourceSpaceAppRels(sourceSpaceAppRels)
142→                .build();
143→        
144→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
145→                spaceNodeTree, 
146→                task.getTargetSpaceId(),
147→                task.getSourceSpaceId(),
148→                migrationType, 
149→                migrationConfig
150→        );
151→        
152→        log.info("Overall migration completed: success={}, failed={}, total mappings={}", 
153→                overallResult.getSuccessCount(), overallResult.getFailedCount(), 
154→                overallResult.getNodeIdMapping().size());
155→
156→        // 迁移中遇到错误抛异常并终止迁移
157→        if (overallResult.getErrorMessage() != null) {
158→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
159→            throw new BusinessException(overallResult.getErrorMessage());
160→        }
161→
162→        // 迁移后的节点重新构建成树并入库
163→        saveNewNodeTree(spaceNodeTree, task.getTargetSpaceId(), overallResult.getNodeIdMapping(), userId);
164→        // 判断是空间站内迁移并且保留状态是false，调用文件删除接口，把源文件删除
165→        if (!task.getIsRemained() && task.getType().equals(MigrationTypeEnum.INTRA_SERVER.getValue())) {
166→            for (TreeNode<SpaceNodeVo> treeNode : spaceNodeTree) {
167→                spaceNodeUpdateManager.deleteSpaceNode(treeNode.getRelId(), userId);
168→            }
169→        }
170→    }
171→
172→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId, Map<String, String> nodeIdMapping, Long userId) {
173→        if (originalTree == null || originalTree.isEmpty()) {
174→            log.info("No tree nodes to save for space: {}", spaceId);
175→            return;
176→        }
177→
178→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
179→
180→        for (TreeNode<SpaceNodeVo> node : originalTree) {
181→            saveNodeAndChildren(node, spaceId, nodeIdMapping, ROOT_PARENT_ID, userId);
182→        }
183→
184→        log.info("Completed saving new node tree for space: {}", spaceId);
185→    }
186→
187→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping, Long parentId, Long userId) {
188→        SpaceNodeVo spaceNodeVo = node.getData();
189→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
190→        String newNodeId = nodeIdMapping.get(oldNodeId);
191→
192→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
193→            newNodeId = "";
194→        }
195→
196→        if (newNodeId == null) {
197→            log.error("No mapping found for node: {}", oldNodeId);
198→            return;
199→        }
200→
201→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
202→                .appSpaceNodeId(newNodeId)
203→                .name(spaceNodeVo.getName())
204→                .type(spaceNodeVo.getType())
205→                .appSpaceNodeId(newNodeId)
206→                .description(spaceNodeVo.getDescription())
207→                .spaceId(spaceId)
208→                .createdBy(userId)
209→                .updatedBy(userId)
210→                .build();
211→
212→        spaceNodeService.save(spaceNodeEntity);
213→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
214→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
215→
216→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
217→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
218→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId);
219→            }
220→        }
221→    }
222→
223→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
224→        ObjectMapper mapper = objectMapper.copy();
225→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
226→        SimpleModule module = new SimpleModule();
227→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
228→        mapper.registerModule(module);
229→        JavaType treeNodeType =
230→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
231→        JavaType listType =
232→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
233→        return mapper.readValue(json, listType);
234→    }
235→
236→}

