 22→/**
 23→ * Outline 应用跨服务器迁移
 24→ */
 25→@Slf4j
 26→@Service
 27→public class OutlineCrossMigrationServiceImpl implements ThirdAppMigrationService {
 28→    @Resource
 29→    private IApitableGrpcClientService apitableGrpcClientService;
 30→
 31→    @Resource
 32→    private ConstProperties constProperties;
 33→
 34→    @Resource
 35→    private OutlineService outlineService;
 36→
 37→    @Override
 38→    public Collection<SpaceNodeTypeEnum> supportedSpaceNodeTypes() {
 39→        return SpaceNodeTypeEnum.OUTLINE_TYPES;
 40→    }
 41→
 42→    @Override
 43→    public boolean supportsMigrationType(MigrationTypeEnum migrationType) {
 44→        return migrationType == MigrationTypeEnum.CROSS_SERVER;
 45→    }
 46→
 47→    @Override
 48→    public SpaceNodeMigrationResult handleMigration(List<SpaceNodeVo> spaceNodes,
 49→                                                    String targetSpaceId,
 50→                                                    String sourceSpaceId,
 51→                                                    MigrationTypeEnum migrationType,
 52→                                                    MigrationConfig migrationConfig) {
 53→        log.info("Starting Outline cross-server migration for {} nodes", spaceNodes.size());
 54→
 55→        if (spaceNodes.isEmpty()) {
 56→            log.info("No Outline nodes found for migration");
 57→            return SpaceNodeMigrationResult.builder()
 58→                    .successCount(0)
 59→                    .failedCount(0)
 60→                    .build();
 61→        }
 62→
 63→        String email = migrationConfig.getEmail();
 64→        UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(email);
 65→        Long userId = user.getId();
 66→
 67→        List<String> apitableNodeIds = spaceNodes.stream().map(SpaceNodeVo::getAppSpaceNodeId).toList();
 68→        log.info("start exportNodeToSpaceCopyFromMirror, apitableNodeIds: {}", apitableNodeIds);
 69→        String downloadUrl = apitableGrpcClientService.exportNodeToSpaceCopyFromMirror(sourceSpaceId, apitableNodeIds);
 70→        log.info("exportNodeToSpaceCopyFromMirror, downloadUrl: {}", downloadUrl);
 71→        apitableGrpcClientService.importNodeToSpaceCopy(downloadUrl, constProperties.getAssetDomainInEx());
 72→
 73→        Map<String, String> nodeIdMapping = new HashMap<>();
 74→        int successCount = 0;
 75→        int failedCount = 0;
 76→
 77→        for (SpaceNodeVo node : spaceNodes) {
 78→            try {
 79→                String nodeId = node.getAppSpaceNodeId();
 80→                String newNodeId = apitableGrpcClientService.copyNodeToSpace(userId, targetSpaceId, "", nodeId, true);
 81→                outlineMigrate(nodeId, newNodeId, targetSpaceId, email);
 82→                nodeIdMapping.put(nodeId, newNodeId);
 83→                successCount++;
 84→            } catch (Exception e) {
 85→                log.error("Failed to copy node {} to space {}", node.getAppSpaceNodeId(), targetSpaceId, e);
 86→                failedCount++;
 87→            }
 88→        }
 89→
 90→        return SpaceNodeMigrationResult.builder()
 91→                .nodeIdMapping(nodeIdMapping)
 92→                .successCount(successCount)
 93→                .failedCount(failedCount)
 94→                .build();
 95→    }
 96→
 97→    private void outlineMigrate(String nodeId, String newNodeId, String targetSpaceId, String email) {
 98→        log.info("迁移 outline 文档内容, {} -> {}", nodeId, newNodeId);
 99→        String downloadUrl = outlineService.exportDoc(nodeId, email);
100→        log.info("导出文档到 minio: {}", downloadUrl);
101→        if (downloadUrl == null) {
102→            throw new RuntimeException("导出文档到 minio 失败");
103→        }
104→        outlineService.importDocToPrivate(downloadUrl, targetSpaceId, email, newNodeId);
105→        log.info("outline 文档内容导入成功, {} -> {}", nodeId, newNodeId);
106→    }
107→}
