 28→/**
 29→ * Apitable应用跨服务器迁移, 只在内网的collabspace-private执行, affine-mirror的数据导入内网affine
 30→ */
 31→@Slf4j
 32→@Service
 33→public class AffineCrossMigrationServiceImpl implements ThirdAppMigrationService {
 34→    @Resource
 35→    private AffineService affineService;
 36→
 37→    @Resource
 38→    private ISpaceAppRelService spaceAppRelService;
 39→
 40→    @Resource
 41→    private SpaceNodeMigrationQueryManager spaceNodeMigrationQueryManager;
 42→
 43→    @Resource
 44→    CollabspaceGrpcClientServiceImpl collabspaceGrpcClientService;
 45→
 46→    @Override
 47→    public Collection<SpaceNodeTypeEnum> supportedSpaceNodeTypes() {
 48→        return SpaceNodeTypeEnum.AFFINE_TYPES;
 49→    }
 50→
 51→    @Override
 52→    public boolean supportsMigrationType(MigrationTypeEnum migrationType) {
 53→        return migrationType == MigrationTypeEnum.CROSS_SERVER;
 54→    }
 55→
 56→    @Override
 57→    public SpaceNodeMigrationResult handleMigration(List<SpaceNodeVo> spaceNodes,
 58→                                                    String targetSpaceId,
 59→                                                    String sourceSpaceId,
 60→                                                    MigrationTypeEnum migrationType,
 61→                                                    MigrationConfig migrationConfig) {
 62→
 63→        if (spaceNodes.isEmpty()) {
 64→            log.info("No Affine nodes found for migration");
 65→            return SpaceNodeMigrationResult.builder()
 66→                    .successCount(0)
 67→                    .failedCount(0)
 68→                    .build();
 69→        }
 70→        List<String> affineNodeIds = spaceNodes.stream().map(SpaceNodeVo::getAppSpaceNodeId).toList();
 71→        // 从 migrationConfig 中获取复制来源空间站对应的 Affine 空间站 id
 72→        String sourceAffineSpaceId = migrationConfig.getSourceSpaceAppRels().stream()
 73→                .filter(appRel -> Objects.equals(appRel.getAppType(), 2))
 74→                .map(SpaceAppRelVo::getAppSpaceId)
 75→                .findFirst()
 76→                .orElse(null);
 77→        log.info("处理 sourceSpaceId, 获取 Affine 应用内的 spaceId: {} -> {}", sourceSpaceId, sourceAffineSpaceId);
 78→        if (sourceAffineSpaceId == null) {
 79→            throw new Error("获取复制来源空间站对应的 Affine 空间站 id 失败");
 80→        }
 81→        String email = migrationConfig.getEmail();
 82→        List<SpaceVo> spaceVos = collabspaceGrpcClientService.listManagedSpaceForMigration(email);
 83→        log.info("private spaceVos: {}", spaceVos);
 84→        Optional<SpaceAppRelEntity> spaceAppRel = spaceAppRelService.listBySpaceIdAndAppType(targetSpaceId, 2).stream().findFirst();
 85→        String targetAffineSpaceId = spaceAppRel.map(SpaceAppRelEntity::getAppSpaceId).orElse(null);
 86→        log.info("处理 targetSpaceId, 获取 Affine 应用内的 spaceId: {} -> {}", targetSpaceId, targetAffineSpaceId);
 87→        if (targetAffineSpaceId == null) {
 88→            throw new Error("获取模板空间站对应的 Affine 空间站 id 失败");
 89→        }
 90→
 91→        Map<String, String> nodeIdMapping = new HashMap<>();
 92→        int successCount = 0;
 93→        int failedCount = 0;
 94→        try {
 95→            log.info("开始导出文档 docIds: {}; spaceId: {}", affineNodeIds, sourceAffineSpaceId);
 96→            String downloadUrl = affineService.exportDoc(affineNodeIds, sourceAffineSpaceId, targetAffineSpaceId);
 97→            log.info("导出文档到 minio: {}", downloadUrl);
 98→            if (downloadUrl == null) {
 99→                throw new Error("导出文档到 minio 失败");
100→            }
101→            nodeIdMapping = affineService.importDocToPrivate(downloadUrl, targetAffineSpaceId, email);
102→            log.info("导入成功: {}", nodeIdMapping);
103→            successCount+=spaceNodes.toArray().length;
104→        } catch (Exception e) {
105→            log.error("Failed to copy node {} to space {}", spaceNodes, targetSpaceId, e);
106→            failedCount+=spaceNodes.toArray().length;
107→        }
108→
109→
110→        return SpaceNodeMigrationResult.builder()
111→                .nodeIdMapping(nodeIdMapping)
112→                .successCount(successCount)
113→                .failedCount(failedCount)
114→                .build();
115→    }
116→
117→}
